// Loop through items in case multiple run at once
for (const item of items) {
  try {
    const rawOutput = item.json.output;
    let parsedData;

    // CHECK 1: Is it already an Object? (n8n auto-parsed it)
    if (typeof rawOutput === 'object' && rawOutput !== null) {
      parsedData = rawOutput;
    } 
    // CHECK 2: Is it a String? (Needs cleaning & parsing)
    else if (typeof rawOutput === 'string') {
      // Remove markdown blocks like ```json ... ```
      const cleanJson = rawOutput.replace(/^```json\s*|\s*```$/g, '');
      parsedData = JSON.parse(cleanJson);
    }

    // Merge the parsed data back into the item
    // You will now have 'has_issues', 'vulnerabilities', etc. as top-level keys
    Object.assign(item.json, parsedData);

  } catch (error) {
    // Fallback if parsing fails
    item.json.error = "Failed to parse JSON";
    item.json.raw_response = item.json.output;
  }
}

return items;

